-- ════════════════════════════════════════════════════════════════
-- V47 : Tous les pays du monde (ISO 3166-1) — nom FR, ISO-2, ISO-3,
-- drapeau, indicatif. L'app affiche le NOM ; elle stocke le code ISO
-- (jamais saisi a la main). Prepare l'internationalisation (nom
-- localisable par code ISO). Portable / rejouable.
-- ════════════════════════════════════════════════════════════════

-- Colonne ISO-2 (les fiches persons.origin_country/residence_country sont en ISO-2 ;
-- villages.country reste en ISO-3 = countries.code).
ALTER TABLE countries ADD COLUMN IF NOT EXISTS iso2 CHAR(2);


CREATE UNIQUE INDEX IF NOT EXISTS uq_countries_iso2 ON countries(iso2) WHERE iso2 IS NOT NULL;
